class ProductsController < ApplicationController
  def index
    @products = Product.all

    if params[:search].present?
      search = params[:search]

      if search[:name].present?
        @products = @products.where("products.name ILIKE '%#{sanitize_sql_like(search[:name])}%'")
      end

      if search[:category].present?
        @products = @products.where("products.category = '#{search[:category].to_s.gsub("'", "''")}'")
      end

      if search[:min_price].present?
        @products = @products.where("products.price >= #{search[:min_price].to_f}")
      end

      if search[:max_price].present?
        @products = @products.where("products.price <= #{search[:max_price].to_f}")
      end
    end

    @products = @products.order(created_at: :desc)
  end

